package main
import "fmt"

func figurinhasRepetidas (figs[]int) int {
	repetidas := make(map[int]int)

	for _,valor := range figs {
		repetidas[valor]++

		if repetidas[valor] > 1 {
			return valor
		}
	}
	return -1
}

func numeroFaltando(figs []int, total int) string {
	controle := make(map[int]bool)

	for _, valor := range figs {
		controle[valor] = true
	}

	maior := 0

	for _, valor := range figs{
		if valor > maior {
			maior = valor
		}
	}

	for i := 1; i <= maior; i++ {
		if controle[i] == false {
			return fmt.Sprintf( "%d", i)
		}
	}
	return "N"
}

func main () {
	var total_figurinhas int
	var qtd int

	fmt.Scan(&total_figurinhas,&qtd)
	figs := make([]int, qtd)


	for i:=0; i < qtd; i++ {
		fmt.Scan(&figs[i])
	}

	fmt.Println(figurinhasRepetidas(figs))
	fmt.Println(numeroFaltando(figs,total_figurinhas))
}
